B.a14=new A.dl("Check for response",'Tap shoulders firmly, shout "Are you OK?". If unresponsive, call emergency services immediately.')
B.a1_=new A.dl("Open the airway","Head-tilt chin-lift: one hand on forehead, two fingers under chin. Tilt back to open airway.")
